# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric._test_extrig","kind":"function","src_hash":"9ffdb7786234f3d0","in":{"base":"Any"},"out":{"base":"Any","pred":"unchanged(f, i) and expand_trig(f(i)) == f(i) and expand_trig(f(Mul(i, 1, evaluate=False))) == e and abs(f(i) - e).n() < 1e-10"},"spec":{"lhs":"_test_extrig(f, )","rhs":"internal helper behaves correctly","over":{"base":"Any"},"name":"_test_extrig_correct"},"guarantee":"internal helper behaves correctly","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric._test_extrig_correct","statement":"Path(_test_extrig(x), internal helper behaves correctly)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a6232fe8bba1901a"}
def _test_extrig(f, i, e):
    from sympy.core.function import expand_trig
    assert unchanged(f, i)
    assert expand_trig(f(i)) == f(i)
    # testing directly instead of with .expand(trig=True)
    # because the other expansions undo the unevaluated Mul
    assert expand_trig(f(Mul(i, 1, evaluate=False))) == e
    assert abs(f(i) - e).n() < 1e-10


