# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_sin_expansion","kind":"function","src_hash":"7679a0d1478d27ed","in":{"base":"Any"},"out":{"base":"Any","pred":"sin(x + y).expand(trig=True) == sin(x) * cos(y) + cos(x) * sin(y) and sin(x - y).expand(trig=True) == sin(x) * cos(y) - cos(x) * sin(y) and sin(y - x).expand(trig=True) == cos(x) * sin(y) - sin(x) * cos(y) and sin(2 * x).expand(trig=True) == 2 * sin(x) * cos(x) and sin(3 * x).expand(trig=True) == -4 * sin(x) ** 3 + 3 * sin(x) and sin(4 * x).expand(trig=True) == -8 * sin(x) ** 3 * cos(x) + 4 * sin(x) * cos(x) and sin(2 * pi / 17).expand(trig=True) == sin(2 * pi / 17, evaluate=False)"},"spec":{"lhs":"test_sin_expansion()","rhs":"test_sin_expansion produces the expected output","over":{"base":"Any"},"name":"test_sin_expansion_correct"},"guarantee":"test_sin_expansion produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_sin_expansion_correct","statement":"Path(test_sin_expansion(x), test_sin_expansion produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8c1e513aec543194"}
def test_sin_expansion():
    # Note: these formulas are not unique.  The ones here come from the
    # Chebyshev formulas.
    assert sin(x + y).expand(trig=True) == sin(x)*cos(y) + cos(x)*sin(y)
    assert sin(x - y).expand(trig=True) == sin(x)*cos(y) - cos(x)*sin(y)
    assert sin(y - x).expand(trig=True) == cos(x)*sin(y) - sin(x)*cos(y)
    assert sin(2*x).expand(trig=True) == 2*sin(x)*cos(x)
    assert sin(3*x).expand(trig=True) == -4*sin(x)**3 + 3*sin(x)
    assert sin(4*x).expand(trig=True) == -8*sin(x)**3*cos(x) + 4*sin(x)*cos(x)
    assert sin(2*pi/17).expand(trig=True) == sin(2*pi/17, evaluate=False)
    assert sin(x+pi/17).expand(trig=True) == sin(pi/17)*cos(x) + cos(pi/17)*sin(x)
    _test_extrig(sin, 2, 2*sin(1)*cos(1))
    _test_extrig(sin, 3, -4*sin(1)**3 + 3*sin(1))


