# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_cot_rewrite","kind":"function","src_hash":"58f59a92db934837","in":{"base":"Any"},"out":{"base":"Any","pred":"cot(x).rewrite(exp) == I * (pos_exp + neg_exp) / (pos_exp - neg_exp) and cot(x).rewrite(sin) == sin(2 * x) / (2 * sin(x) ** 2) and cot(x).rewrite(cos) == cos(x) / cos(x - pi / 2, evaluate=False) and cot(x).rewrite(tan) == 1 / tan(x) and cot(log(x)).rewrite(Pow) == -I * (x ** (-I) + x ** I) / (x ** (-I) - x ** I) and cot(x).rewrite(sec) == sec(x - pi / 2, evaluate=False) / sec(x) and cot(x).rewrite(csc) == csc(x) / csc(-x + pi / 2, evaluate=False) and cot(sin(x)).rewrite(Pow) == cot(sin(x)) and cot(x).rewrite(besselj) == besselj(-S.Half, x) / besselj(S.Half, x) and cot(x).rewrite(besselj).subs(x, 0) == cot(0) and z.rewrite(exp).expand() == 0"},"spec":{"lhs":"test_cot_rewrite()","rhs":"test_cot_rewrite produces the expected output","over":{"base":"Any"},"name":"test_cot_rewrite_correct"},"guarantee":"test_cot_rewrite produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_cot_rewrite_correct","statement":"Path(test_cot_rewrite(x), test_cot_rewrite produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9cafc829d27895af"}
def test_cot_rewrite():
    neg_exp, pos_exp = exp(-x*I), exp(x*I)
    assert cot(x).rewrite(exp) == I*(pos_exp + neg_exp)/(pos_exp - neg_exp)
    assert cot(x).rewrite(sin) == sin(2*x)/(2*(sin(x)**2))
    assert cot(x).rewrite(cos) == cos(x)/cos(x - pi/2, evaluate=False)
    assert cot(x).rewrite(tan) == 1/tan(x)
    def check(func):
        z = cot(func(x)).rewrite(exp) - cot(x).rewrite(exp).subs(x, func(x))
        assert z.rewrite(exp).expand() == 0
    check(sinh)
    check(cosh)
    check(tanh)
    check(coth)
    check(sin)
    check(cos)
    check(tan)
    assert cot(log(x)).rewrite(Pow) == -I*(x**-I + x**I)/(x**-I - x**I)
    assert cot(x).rewrite(sec) == sec(x - pi / 2, evaluate=False) / sec(x)
    assert cot(x).rewrite(csc) == csc(x) / csc(- x + pi / 2, evaluate=False)
    assert cot(sin(x)).rewrite(Pow) == cot(sin(x))
    assert cot(pi*Rational(2, 5), evaluate=False).rewrite(sqrt) == (Rational(-1, 4) + sqrt(5)/4)/\
                                                        sqrt(sqrt(5)/8 + Rational(5, 8))
    assert cot(x).rewrite(besselj) == besselj(-S.Half, x)/besselj(S.Half, x)
    assert cot(x).rewrite(besselj).subs(x, 0) == cot(0)


