# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_atan_leading_term","kind":"function","src_hash":"4e5e51b3f72e6c8a","in":{"base":"Any"},"out":{"base":"Any","pred":"atan(x).as_leading_term(x) == x and atan(1 / x).as_leading_term(x, cdir=1) == pi / 2 and atan(1 / x).as_leading_term(x, cdir=-1) == -pi / 2 and atan(x + 2 * I).as_leading_term(x, cdir=1) == I * atanh(2) and atan(x + 2 * I).as_leading_term(x, cdir=-1) == -pi + I * atanh(2) and atan(x - 2 * I).as_leading_term(x, cdir=1) == pi - I * atanh(2) and atan(x - 2 * I).as_leading_term(x, cdir=-1) == -I * atanh(2)"},"spec":{"lhs":"test_atan_leading_term()","rhs":"test_atan_leading_term produces the expected output","over":{"base":"Any"},"name":"test_atan_leading_term_correct"},"guarantee":"test_atan_leading_term produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_atan_leading_term_correct","statement":"Path(test_atan_leading_term(x), test_atan_leading_term produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"38c742a38a942c55"}
def test_atan_leading_term():
    assert atan(x).as_leading_term(x) == x
    assert atan(1/x).as_leading_term(x, cdir=1) == pi/2
    assert atan(1/x).as_leading_term(x, cdir=-1) == -pi/2
    # Tests concerning branch points
    assert atan(x + I).as_leading_term(x, cdir=1) == -I*log(x)/2 + pi/4 + I*log(2)/2
    assert atan(x + I).as_leading_term(x, cdir=-1) == -I*log(x)/2 - 3*pi/4 + I*log(2)/2
    assert atan(x - I).as_leading_term(x, cdir=1) == I*log(x)/2 + pi/4 - I*log(2)/2
    assert atan(x - I).as_leading_term(x, cdir=-1) == I*log(x)/2 + pi/4 - I*log(2)/2
    # Tests concerning points lying on branch cuts
    assert atan(x + 2*I).as_leading_term(x, cdir=1) == I*atanh(2)
    assert atan(x + 2*I).as_leading_term(x, cdir=-1) == -pi + I*atanh(2)
    assert atan(x - 2*I).as_leading_term(x, cdir=1) == pi - I*atanh(2)
    assert atan(x - 2*I).as_leading_term(x, cdir=-1) == -I*atanh(2)
    # Tests concerning re(ndir) == 0
    assert atan(2*I - I*x - x**2).as_leading_term(x, cdir=1) == -pi/2 + I*log(3)/2
    assert atan(2*I - I*x - x**2).as_leading_term(x, cdir=-1) == -pi/2 + I*log(3)/2


