# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_evenodd_rewrite","kind":"function","src_hash":"e7d11f5c80519480","in":{"base":"Any"},"out":{"base":"Any","pred":"_check_no_rewrite(func, a * b) and func(x - y) == func(y - x) and _check_no_rewrite(func, a * b) and func(x - y) == -func(y - x) and _check_even_rewrite(func, expr) and _check_odd_rewrite(func, expr)"},"spec":{"lhs":"test_evenodd_rewrite()","rhs":"test_evenodd_rewrite produces the expected output","over":{"base":"Any"},"name":"test_evenodd_rewrite_correct"},"guarantee":"test_evenodd_rewrite produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_evenodd_rewrite_correct","statement":"Path(test_evenodd_rewrite(x), test_evenodd_rewrite produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"60fc04a8f2846c80"}
def test_evenodd_rewrite():
    a = cos(2)  # negative
    b = sin(1)  # positive
    even = [cos]
    odd = [sin, tan, cot, asin, atan, acot]
    with_minus = [-1, -2**1024 * E, -pi/105, -x*y, -x - y]
    for func in even:
        for expr in with_minus:
            assert _check_even_rewrite(func, expr)
        assert _check_no_rewrite(func, a*b)
        assert func(
            x - y) == func(y - x)  # it doesn't matter which form is canonical
    for func in odd:
        for expr in with_minus:
            assert _check_odd_rewrite(func, expr)
        assert _check_no_rewrite(func, a*b)
        assert func(
            x - y) == -func(y - x)  # it doesn't matter which form is canonical


