# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_atan2_expansion","kind":"function","src_hash":"16077e1641aae2ce","in":{"base":"Any"},"out":{"base":"Any","pred":"cancel(atan2(x ** 2, x + 1).diff(x) - atan(x ** 2 / (x + 1)).diff(x)) == 0"},"spec":{"lhs":"test_atan2_expansion()","rhs":"test_atan2_expansion produces the expected output","over":{"base":"Any"},"name":"test_atan2_expansion_correct"},"guarantee":"test_atan2_expansion produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_atan2_expansion_correct","statement":"Path(test_atan2_expansion(x), test_atan2_expansion produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"84a7ab766c3016fb"}
def test_atan2_expansion():
    assert cancel(atan2(x**2, x + 1).diff(x) - atan(x**2/(x + 1)).diff(x)) == 0
    assert cancel(atan(y/x).series(y, 0, 5) - atan2(y, x).series(y, 0, 5)
                  + atan2(0, x) - atan(0)) == O(y**5)
    assert cancel(atan(y/x).series(x, 1, 4) - atan2(y, x).series(x, 1, 4)
                  + atan2(y, 1) - atan(y)) == O((x - 1)**4, (x, 1))
    assert cancel(atan((y + x)/x).series(x, 1, 3) - atan2(y + x, x).series(x, 1, 3)
                  + atan2(1 + y, 1) - atan(1 + y)) == O((x - 1)**3, (x, 1))
    assert Matrix([atan2(y, x)]).jacobian([y, x]) == \
        Matrix([[x/(y**2 + x**2), -y/(y**2 + x**2)]])


