# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_inverses","kind":"function","src_hash":"0b5e6c4795a27525","in":{"base":"Any"},"out":{"base":"Any","pred":"tan(x).inverse() == atan and cot(x).inverse() == acot and asin(x).inverse() == sin and acos(x).inverse() == cos and atan(x).inverse() == tan and acot(x).inverse() == cot"},"spec":{"lhs":"test_inverses()","rhs":"test_inverses produces the expected output","over":{"base":"Any"},"name":"test_inverses_correct"},"guarantee":"test_inverses produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_inverses_correct","statement":"Path(test_inverses(x), test_inverses produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"779333193455f394"}
def test_inverses():
    raises(AttributeError, lambda: sin(x).inverse())
    raises(AttributeError, lambda: cos(x).inverse())
    assert tan(x).inverse() == atan
    assert cot(x).inverse() == acot
    raises(AttributeError, lambda: csc(x).inverse())
    raises(AttributeError, lambda: sec(x).inverse())
    assert asin(x).inverse() == sin
    assert acos(x).inverse() == cos
    assert atan(x).inverse() == tan
    assert acot(x).inverse() == cot


