# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_trigonometric.test_trig_period","kind":"function","src_hash":"562bba346a8fc7b2","in":{"base":"Any"},"out":{"base":"Any","pred":"sin(x).period() == 2 * pi and cos(x).period() == 2 * pi and tan(x).period() == pi and cot(x).period() == pi and sec(x).period() == 2 * pi and csc(x).period() == 2 * pi and sin(2 * x).period() == pi and cot(4 * x - 6).period() == pi / 4 and cos(-3 * x).period() == pi * Rational(2, 3) and cos(x * y).period(x) == 2 * pi / abs(y) and sin(3 * x * y + 2 * pi).period(y) == 2 * pi / abs(3 * x) and tan(3 * x).period(y) is S.Zero"},"spec":{"lhs":"test_trig_period()","rhs":"test_trig_period produces the expected output","over":{"base":"Any"},"name":"test_trig_period_correct"},"guarantee":"test_trig_period produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_trigonometric.test_trig_period_correct","statement":"Path(test_trig_period(x), test_trig_period produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8976bb5a2c54be5d"}
def test_trig_period():
    x, y = symbols('x, y')

    assert sin(x).period() == 2*pi
    assert cos(x).period() == 2*pi
    assert tan(x).period() == pi
    assert cot(x).period() == pi
    assert sec(x).period() == 2*pi
    assert csc(x).period() == 2*pi
    assert sin(2*x).period() == pi
    assert cot(4*x - 6).period() == pi/4
    assert cos((-3)*x).period() == pi*Rational(2, 3)
    assert cos(x*y).period(x) == 2*pi/abs(y)
    assert sin(3*x*y + 2*pi).period(y) == 2*pi/abs(3*x)
    assert tan(3*x).period(y) is S.Zero
    raises(NotImplementedError, lambda: sin(x**2).period(x))


